import { SourceResult, SourceType, SourceCategory } from '../types';
import { getAnimeData } from './jikanService';

const ALLANIME_API = 'https://api.allanime.day/api';
const PROXY = 'https://test.cors.workers.dev/?';

const GQL_SEARCH = `
query($search: SearchInput, $limit: Int, $page: Int, $translationType: String) {
  shows(search: $search, limit: $limit, page: $page, translationType: $translationType) {
    edges {
      node {
        _id
        name
        englishName
        availableEpisodesDetail
      }
    }
  }
}`;

const GQL_EPISODE = `
query($showId: String!, $episodeString: String!, $translationType: String!) {
  episode(showId: $showId, episodeString: $episodeString, translationType: $translationType) {
    sourceUrls
  }
}`;

async function gqlRequest(query: string, variables: any) {
  const response = await fetch(`${PROXY}${encodeURIComponent(ALLANIME_API)}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Origin': 'https://allanime.to',
      'Referer': 'https://allanime.to/'
    },
    body: JSON.stringify({ query, variables })
  });
  const json = await response.json();
  return json.data;
}

export const getAnimeEpisodeSources = async (
  malId: number, 
  episodeNumber: number, 
  category: SourceCategory
): Promise<SourceResult[]> => {
  try {
    const anime = await getAnimeData(malId);
    const searchName = `${anime.title_english || anime.title} ${anime.year || ''}`.trim();

    // Map internal category to AllAnime translation type
    const translationType = category === 'dub' ? 'dub' : 'sub';

    const searchData = await gqlRequest(GQL_SEARCH, {
      search: { name: searchName },
      limit: 1,
      translationType
    });

    const show = searchData?.shows?.edges?.[0]?.node;
    if (!show) throw new Error('Anime not found in AllAnime catalog');

    const epData = await gqlRequest(GQL_EPISODE, {
      showId: show._id,
      episodeString: episodeNumber.toString(),
      translationType
    });

    const sources = epData?.episode?.sourceUrls || [];

    return sources.map((src: any) => {
      // Decode URL (AllAnime often encodes them or uses specific formats)
      // This is a simplified version for the demo bridging
      let url = src.sourceUrl;
      if (src.sourceName.toLowerCase().includes('hls')) {
        // Handle common HLS source mapping
        return {
          url: url.startsWith('http') ? url : `https://${url}`,
          type: SourceType.DIRECT,
          provider: 'AllAnime',
          pluginName: src.sourceName,
          label: `${src.sourceName} (${category.toUpperCase()})`,
          category: category
        };
      }
      return {
        url: url,
        type: SourceType.EMBED,
        provider: 'AllAnime',
        pluginName: src.sourceName,
        label: `${src.sourceName} Embed`,
        category: category
      };
    });
  } catch (error) {
    console.error('AllAnime Bridge Error:', error);
    return [];
  }
};

import { SourcePlugin, SourceType, SourceResult } from '../types';
import { getAnimeEpisodeSources } from './allAnimeService';

export const resolveSource = async (
  plugin: SourcePlugin,
  malId: number,
  episodeNumber: number
): Promise<SourceResult[]> => {
  // If the plugin is AllAnime, use our new bridge service
  if (plugin.provider === 'AllAnime') {
    const sources = await getAnimeEpisodeSources(malId, episodeNumber, plugin.category);
    if (sources.length > 0) return sources;
  }

  // Fallback/Existing Logic
  if (plugin.type === SourceType.EMBED) {
    const url = (plugin.getVideoUrlTemplate || plugin.url)
      .replace('{animeId}', malId.toString())
      .replace('{episodeNumber}', episodeNumber.toString());

    return [{
      url,
      type: SourceType.EMBED,
      provider: plugin.provider,
      pluginName: plugin.name,
      label: plugin.label,
      category: plugin.category
    }];
  }

  // Demo fallback
  return [{
    url: plugin.url,
    keyUrl: plugin.keyUrl,
    type: SourceType.DIRECT,
    provider: plugin.provider,
    pluginName: plugin.name,
    label: plugin.label,
    category: plugin.category
  }];
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Anime, Episode, SourcePlugin, SourceResult, User, SourceCategory } from './types';
