function normalizeTitle(title: string) {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}

const App: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const params = useParams();

