    setIsAppending(true);
    setTimeout(() => {
      const nextPage = batchPage + 1;
      const end = nextPage * BATCH_SIZE;
      setDisplayedEpisodes(allEpisodes.slice(0, end));
      setBatchPage(nextPage);
      setIsAppending(false);
    }, 400);
  };

  // Deep Linking Effect
  useEffect(() => {
    const pathParts = location.pathname.split('/').filter(Boolean);
    const malId = pathParts[1];
    const epNum = pathParts[3];

    const syncFromUrl = async () => {
      if (!malId) {
        setSelectedAnime(null);
        setSelectedEpisode(null);
        setActiveSource(null);
        setIsInitialLoading(false);
        return;
      }

      const id = parseInt(malId);
      if (isNaN(id)) return;

      if (!selectedAnime || selectedAnime.mal_id !== id) {
        setIsSearching(true);
        try {
          const animeData = await getAnimeData(id);
          setSelectedAnime(animeData);
          const episodes = initEpisodes(animeData);

          if (epNum) {
            const num = parseInt(epNum);
            const foundEp = episodes.find(e => e.number === num);
            if (foundEp) {
              handleSelectEpisode(foundEp, animeData);
            }
          }
        } catch (err) {
          console.error("Deep link sync failed:", err);
          navigate('/');
        } finally {
          setIsSearching(false);
          setIsInitialLoading(false);
        }
      } else if (epNum) {
        const num = parseInt(epNum);
        if (selectedEpisode?.number !== num) {
