import { SourceResult, SourceType, SourceCategory, AllAnimeSource } from '../types';
import { getAnimeData } from './jikanService';

const ALLANIME_API = 'https://api.allanime.day/api';
const ALLANIME_BASE = 'https://allanime.day';
const PROXY = 'https://test.cors.workers.dev/?';

const GQL_SEARCH = `
query($search: SearchInput, $limit: Int, $page: Int, $translationType: String) {
  shows(search: $search, limit: $limit, page: $page, translationType: $translationType) {
    edges {
      node {
        _id
        name
        englishName
      }
    }
  }
}`;

const GQL_EPISODE = `
query($showId: String!, $episodeString: String!, $translationType: String!) {
  episode(showId: $showId, episodeString: $episodeString, translationType: $translationType) {
    sourceUrls
  }
}`;

async function gqlRequest(query: string, variables: any) {
  const response = await fetch(`${PROXY}${encodeURIComponent(ALLANIME_API)}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Origin': 'https://allanime.to',
      'Referer': 'https://allanime.to/'
    },
    body: JSON.stringify({ query, variables })
  });
  const json = await response.json();
  return json.data;
}

export const getAnimeEpisodeSources = async (
  malId: number, 
  episodeNumber: number, 
  category: SourceCategory
): Promise<SourceResult[]> => {
  try {
    const anime = await getAnimeData(malId);
    const searchName = `${anime.title_english || anime.title} ${anime.year || ''}`.trim();
    const translationType = category === 'dub' ? 'dub' : 'sub';

    const searchData = await gqlRequest(GQL_SEARCH, {
      search: { name: searchName },
      limit: 1,
      translationType
    });

    const show = searchData?.shows?.edges?.[0]?.node;
    if (!show) throw new Error('Anime not found in AllAnime catalog');

    const epData = await gqlRequest(GQL_EPISODE, {
      showId: show._id,
      episodeString: episodeNumber.toString(),
      translationType
    });

    const sources = epData?.episode?.sourceUrls || [];

    return sources.map((src: any) => {
      const isPlayer = src.sourceName.toLowerCase().includes('hls') || src.sourceName.toLowerCase().includes('mp4');

      const rawSource: AllAnimeSource = {
        name: src.sourceName,
        type: isPlayer ? 'player' : 'iframe',
        url: src.sourceUrl
      };

      return {
        url: src.sourceUrl,
        type: isPlayer ? SourceType.DIRECT : SourceType.EMBED,
        provider: 'AllAnime',
        pluginName: src.sourceName,
        label: `${src.sourceName} (${category.toUpperCase()})`,
        category: category,
        rawSource: rawSource
      };
    });
  } catch (error) {
    console.error('AllAnime Bridge Error:', error);
    return [];
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import * as Vidstack from '@vidstack/react';
import { defaultLayoutIcons, DefaultVideoLayout } from '@vidstack/react/player/layouts/default';
import Hls from 'hls.js';
import { SourceResult, SourceType, AllAnimeSource } from '../types';

const { MediaPlayer } = Vidstack as any;
const MediaProvider = (Vidstack as any).MediaProvider || (Vidstack as any).MediaOutlet || 'div';
const Poster = (Vidstack as any).Poster || (Vidstack as any).MediaPoster || 'div';

interface AnimePlayerProps {
  sources: SourceResult[];
  title: string;
  poster?: string;
  onProgress?: (percent: number) => void;
  onComplete?: () => void;
}

/**
 * Resolves AllAnime specific URL patterns, handling proxies and decoding placeholders.
 */
function resolveSourceUrl(url: string): string {
  if (!url) return '';
  // Check if it's a relative AllAnime API path
  if (url.startsWith('/apivtwo/')) {
    return `https://allanime.day${url}`;
  }
  // AllAnime often uses base64/hex for some internal players, 
  // we treat direct URLs as standard.
  return url;
}

const AnimePlayer: React.FC<AnimePlayerProps> = ({ sources, title, poster, onProgress, onComplete }) => {
  const [activeSourceIndex, setActiveSourceIndex] = useState(0);
  const activeSource = sources[activeSourceIndex] || sources[0];

  const resolvedUrl = useMemo(() => resolveSourceUrl(activeSource?.url), [activeSource]);

  const hlsConfig = useMemo(() => {
    if (!Hls.isSupported()) return {};
    return {
      fetchSetup: (url: string, init: RequestInit) => {
        const isKey = url.includes('.key') || url.includes('/keys/') || (activeSource?.keyUrl && url.includes(activeSource.keyUrl));
        if (isKey) {
          const targetUrl = activeSource?.keyUrl || url;
          return new Request(`https://test.cors.workers.dev/?${encodeURIComponent(targetUrl)}`, init);
        }
        return new Request(url, init);
      },
      xhrSetup: (xhr: XMLHttpRequest) => {
        xhr.withCredentials = false;
      },
      enableWorker: true,
    };
  }, [activeSource]);

  const handleTimeUpdate = (event: any) => {
    if (!event?.detail) return;
    const { currentTime, duration } = event.detail;
    if (duration > 0) {
      const percent = (currentTime / duration) * 100;
      onProgress?.(percent);
      if (percent >= 98) onComplete?.();
    }
  };

  const getServerLabel = (name: string) => {
    const n = name.toLowerCase();
    if (n === 'default') return { text: 'Default', experimental: true };
    if (n.includes('yt')) return { text: 'Yt-mp4', experimental: false };
    if (n.includes('s-mp4')) return { text: 'S-mp4', experimental: false };
    if (n.includes('ok')) return { text: 'Ok', experimental: false };
    return { text: name, experimental: false };
  };

  return (
    <div className="flex flex-col gap-6">
      <div className="flex flex-col lg:flex-row gap-6">
        {/* Player Container */}
        <div className="flex-[3] relative aspect-video bg-zinc-950 rounded-2xl overflow-hidden shadow-2xl border border-white/5">
          {activeSource?.rawSource?.type === 'iframe' ? (
            <div className="w-full h-full bg-black flex flex-col">
              <div className="flex-1">
                <iframe
                  src={resolvedUrl}
                  className="w-full h-full border-0"
                  allowFullScreen
                  sandbox="allow-scripts allow-same-origin allow-forms"
                  referrerPolicy="no-referrer"
                />
              </div>
              <div className="bg-zinc-900 px-4 py-2 border-t border-white/5 flex items-center justify-between">
                <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">
                  Embedded Stream ({activeSource.pluginName})
                </span>
                <span className="text-[10px] text-amber-500 font-bold uppercase tracking-tighter">
                  Limited Controls
                </span>
              </div>
            </div>
          ) : (
            <MediaPlayer
              title={title}
              src={resolvedUrl}
              onTimeUpdate={handleTimeUpdate}
              crossOrigin
              playsInline
              className="w-full h-full"
            >
              <MediaProvider {...({ hlsConfig } as any)}>
                {poster && <Poster src={poster} alt={title} className="vds-poster" />}
              </MediaProvider>
              <DefaultVideoLayout icons={defaultLayoutIcons} />
            </MediaPlayer>
          )}
        </div>

        {/* Server Selection Sidebar */}
        <div className="flex-1 flex flex-col gap-4">
          <div className="bg-zinc-900/50 backdrop-blur-xl rounded-2xl border border-white/5 p-5 h-full">
            <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-zinc-500 mb-6 flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse"></div>
              Server Selection
            </h3>

            <div className="grid grid-cols-1 gap-2 overflow-y-auto max-h-[300px] lg:max-h-none custom-scrollbar pr-2">
              {sources.map((source, index) => {
                const labelInfo = getServerLabel(source.pluginName);
                const isActive = activeSourceIndex === index;

                return (
                  <button
                    key={index}
                    onClick={() => setActiveSourceIndex(index)}
                    className={`group w-full flex items-center justify-between p-4 rounded-xl transition-all border ${
                      isActive 
                        ? 'bg-blue-600/10 border-blue-500/50 shadow-lg' 
                        : 'bg-zinc-800/40 border-transparent hover:bg-zinc-800 hover:border-white/10'
                    }`}
                  >
                    <div className="flex flex-col items-start">
                      <span className={`text-[11px] font-black uppercase tracking-widest ${isActive ? 'text-blue-400' : 'text-zinc-300'}`}>
                        {labelInfo.text}
                      </span>
                      <span className="text-[9px] text-zinc-600 font-bold uppercase">
                        {source.rawSource?.type === 'iframe' ? 'Iframe' : 'Native'}
                      </span>
                    </div>
                    {labelInfo.experimental && (
                      <span className="text-[8px] bg-amber-500/10 text-amber-500 border border-amber-500/20 px-2 py-0.5 rounded-full font-black uppercase">
                        Experimental
                      </span>
                    )}
                  </button>
                );
              })}
            </div>

            <div className="mt-6 pt-6 border-t border-white/5">
              <div className="flex items-center gap-3 opacity-50">
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                <span className="text-[8px] font-black uppercase tracking-widest text-zinc-500">
                  Global Matrix Online
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .vds-poster {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          opacity: 0.15;
          filter: blur(50px);
          transition: opacity 0.5s ease;
        }
        .vds-media-player[data-can-play] .vds-poster {
          opacity: 0;
          pointer-events: none;
        }
      `}</style>
    </div>
  );
};

export default AnimePlayer;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Routes, Route, useNavigate, useParams, useLocation } from 'react-router-dom';
import { Anime, Episode, SourcePlugin, SourceResult, User, SourceCategory } from './types';
import { DEFAULT_PLUGINS } from './constants';
import { searchAnime, getAnimeData } from './services/jikanService';
import { fetchViewer, updateAniListProgress } from './services/anilistService';
import { resolveSource } from './services/pluginService';
import AnimePlayer from './components/AnimePlayer';
import { SearchIcon, PlayIcon, UserIcon } from './components/Icons';

function normalizeTitle(title: string) {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}

const App: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Anime[]>([]);
  const [selectedAnime, setSelectedAnime] = useState<Anime | null>(null);

  const [allEpisodes, setAllEpisodes] = useState<Episode[]>([]);
  const [displayedEpisodes, setDisplayedEpisodes] = useState<Episode[]>([]);
  const [batchPage, setBatchPage] = useState(1);
  const [isAppending, setIsAppending] = useState(false);
  const BATCH_SIZE = 100;

  const [selectedEpisode, setSelectedEpisode] = useState<Episode | null>(null);
  const [availableSources, setAvailableSources] = useState<SourceResult[]>([]);
  const [activePluginId, setActivePluginId] = useState<string>(DEFAULT_PLUGINS[0].id);
  const [user, setUser] = useState<User | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const [token, setToken] = useState<string | null>(localStorage.getItem('anilist_token'));

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.includes('access_token')) {
      const newToken = new URLSearchParams(hash.substring(1)).get('access_token');
      if (newToken) {
        setToken(newToken);
        localStorage.setItem('anilist_token', newToken);
        window.location.hash = '';
      }
    }
  }, []);

  useEffect(() => {
    if (token) {
      fetchViewer(token).then(setUser).catch(() => {
        setToken(null);
        localStorage.removeItem('anilist_token');
      });
    }
  }, [token]);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!searchQuery.trim()) return;
    setIsSearching(true);
    setSelectedAnime(null);
    setSelectedEpisode(null);
    setAvailableSources([]);
    navigate('/');

    try {
      const results = await searchAnime(searchQuery);
      setSearchResults(results);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSearching(false);
    }
  };

  const initEpisodes = (anime: Anime) => {
    const mockCount = anime.episodes || 24;
    const mocks: Episode[] = Array.from({ length: mockCount }, (_, i) => ({
      mal_id: i + 1,
      number: i + 1,
      episode_id: `ep-${i + 1}`,
      title: `${anime.title} - Episode ${i + 1}`,
      aired: new Date().toISOString()
    }));
    setAllEpisodes(mocks);
    setDisplayedEpisodes(mocks.slice(0, BATCH_SIZE));
    setBatchPage(1);
    return mocks;
  };

  const handleSelectAnime = async (anime: Anime) => {
    setSelectedAnime(anime);
    setSearchResults([]);
    setSearchQuery('');
    initEpisodes(anime);
    navigate(`/anime/${anime.mal_id}/${normalizeTitle(anime.title)}`);
  };

  const handleSelectEpisode = useCallback(async (episode: Episode, animeContext?: Anime) => {
    const anime = animeContext || selectedAnime;
    if (!anime) return;

    setSelectedEpisode(episode);
    const plugin = DEFAULT_PLUGINS.find(p => p.id === activePluginId) || DEFAULT_PLUGINS[0];

    // For AllAnime, resolveSource returns multiple possible streams
    const resolved = await resolveSource(plugin, anime.mal_id, episode.number);
    setAvailableSources(resolved);

    navigate(`/anime/${anime.mal_id}/${normalizeTitle(anime.title)}/episode/${episode.number}`);
  }, [activePluginId, selectedAnime, navigate]);

  const loadMoreEpisodes = () => {
    setIsAppending(true);
    setTimeout(() => {
      const nextPage = batchPage + 1;
      const end = nextPage * BATCH_SIZE;
      setDisplayedEpisodes(allEpisodes.slice(0, end));
      setBatchPage(nextPage);
      setIsAppending(false);
    }, 400);
  };

  useEffect(() => {
    const pathParts = location.pathname.split('/').filter(Boolean);
    const malId = pathParts[1];
    const epNum = pathParts[3];

    const syncFromUrl = async () => {
      if (!malId) {
        setSelectedAnime(null);
        setSelectedEpisode(null);
        setAvailableSources([]);
        setIsInitialLoading(false);
        return;
      }

      const id = parseInt(malId);
      if (isNaN(id)) return;

      if (!selectedAnime || selectedAnime.mal_id !== id) {
        setIsSearching(true);
        try {
          const animeData = await getAnimeData(id);
          setSelectedAnime(animeData);
          const episodes = initEpisodes(animeData);

          if (epNum) {
            const num = parseInt(epNum);
            const foundEp = episodes.find(e => e.number === num);
            if (foundEp) {
              handleSelectEpisode(foundEp, animeData);
            }
          }
        } catch (err) {
          console.error("Deep link sync failed:", err);
          navigate('/');
        } finally {
          setIsSearching(false);
          setIsInitialLoading(false);
        }
      } else if (epNum) {
        const num = parseInt(epNum);
        if (selectedEpisode?.number !== num) {
          const foundEp = allEpisodes.find(e => e.number === num);
          if (foundEp) {
            handleSelectEpisode(foundEp);
          }
        }
        setIsInitialLoading(false);
      } else {
        setIsInitialLoading(false);
      }
    };

    syncFromUrl();
  }, [location.pathname]);

  return (
    <div className="min-h-screen flex flex-col bg-slate-950 text-slate-200 selection:bg-blue-500/30">
      <header className="bg-slate-900/40 backdrop-blur-2xl border-b border-white/5 px-8 py-5 flex items-center justify-between sticky top-0 z-[60]">
        <div className="flex items-center gap-4 cursor-pointer group" onClick={() => navigate('/')}>
          <div className="bg-blue-600 p-2.5 rounded-2xl shadow-2xl shadow-blue-600/20 group-hover:scale-105 transition-all">
            <PlayIcon className="text-white" size={24} />
          </div>
          <h1 className="text-2xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-br from-white to-slate-500">
            ZENITH
          </h1>
        </div>

        <form onSubmit={handleSearch} className="flex-1 max-w-lg mx-12 relative hidden md:block">
          <input
            type="text"
            placeholder="Search anime database..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-slate-900/60 border border-white/5 rounded-2xl px-6 py-3.5 focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all text-sm backdrop-blur-md"
          />
          <button type="submit" className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white transition-colors">
            <SearchIcon size={18} />
          </button>
        </form>

        <div className="flex items-center gap-4">
          {user ? (
            <div className="flex items-center gap-3 bg-white/5 px-4 py-2.5 rounded-2xl border border-white/10">
              <img src={user.avatar} alt={user.name} className="w-8 h-8 rounded-full ring-2 ring-blue-500/20" />
              <span className="text-xs font-black uppercase tracking-widest hidden sm:inline">{user.name}</span>
            </div>
          ) : (
            <button 
              onClick={() => window.location.href = `https://anilist.co/api/v2/oauth/authorize?client_id=22153&response_type=token&redirect_uri=${encodeURIComponent(window.location.origin)}`}
              className="bg-slate-800 hover:bg-slate-700 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border border-white/5"
            >
              Sync AniList
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 container mx-auto px-6 py-12">
        {isSearching && (
          <div className="flex flex-col items-center justify-center py-40 space-y-6">
            <div className="w-12 h-12 border-2 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
            <p className="text-slate-500 font-black uppercase tracking-[0.5em] text-[9px]">Analyzing Metadata</p>
          </div>
        )}

        {searchResults.length > 0 && !selectedAnime && !isSearching && (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 xl:grid-cols-6 gap-6">
            {searchResults.map(anime => (
              <div 
                key={anime.mal_id} 
                className="group cursor-pointer bg-slate-900/40 rounded-3xl overflow-hidden border border-white/5 hover:border-blue-500/30 transition-all hover:-translate-y-2 shadow-2xl"
                onClick={() => handleSelectAnime(anime)}
              >
                <div className="aspect-[10/14] relative overflow-hidden">
                  <img src={anime.images.jpg.large_image_url} alt={anime.title} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                  <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-5">
                    <div className="w-full bg-blue-600/90 backdrop-blur-md py-3 rounded-xl text-[10px] font-black uppercase tracking-widest text-center shadow-2xl">Stream Series</div>
                  </div>
                </div>
                <div className="p-4">
                  <h3 className="text-xs font-black line-clamp-1 group-hover:text-blue-400 transition-colors uppercase tracking-tight">{anime.title}</h3>
                  <div className="flex items-center justify-between mt-2">
                    <span className="text-[9px] font-black text-slate-500 uppercase">{anime.year || 'TBA'}</span>
                    <span className="text-[10px] text-yellow-500 font-black">★ {anime.score}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {selectedAnime && !isSearching && (
          <div className="flex flex-col lg:flex-row gap-12 animate-in fade-in duration-700">
            <div className="flex-1 space-y-8">
              {availableSources.length > 0 ? (
                <div className="space-y-8">
                  <AnimePlayer 
                    sources={availableSources} 
                    title={`${selectedAnime.title} - EP ${selectedEpisode?.number}`}
                    poster={selectedAnime.images.jpg.large_image_url}
                    onComplete={() => {
                      if (token && selectedEpisode) updateAniListProgress(token, selectedAnime.mal_id, selectedEpisode.number);
                    }}
                  />

                  <div className="bg-zinc-900/30 p-8 rounded-[2.5rem] border border-white/5 backdrop-blur-xl">
                    <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-10">
                      <div>
                        <div className="flex items-center gap-3 mb-2">
                          <span className="bg-blue-600/20 text-blue-400 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">Episode {selectedEpisode?.number}</span>
                          <span className="text-zinc-600 font-black text-[9px] uppercase tracking-widest">
                            Provider: AllAnime Bridge
                          </span>
                        </div>
                        <h2 className="text-4xl font-black tracking-tighter leading-none">{selectedEpisode?.title}</h2>
                        <p className="mt-4 text-sm text-zinc-500 font-medium leading-relaxed max-w-2xl">
                          Streaming from the zenith node. Multiple high-speed servers are available. Select your preferred latency route from the selection matrix.
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="flex flex-col md:flex-row gap-12">
                   <div className="w-full md:w-72 flex-shrink-0">
                     <img src={selectedAnime.images.jpg.large_image_url} alt={selectedAnime.title} className="w-full rounded-[2.5rem] shadow-3xl border border-white/5" />
                   </div>
                   <div className="flex-1 space-y-8">
                     <div className="space-y-4">
                        <h2 className="text-6xl font-black tracking-tighter leading-[0.85]">{selectedAnime.title}</h2>
                        <div className="flex flex-wrap gap-3">
                          <span className="bg-blue-600/10 text-blue-400 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border border-blue-500/20">{selectedAnime.status}</span>
                          <span className="bg-white/5 text-slate-400 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border border-white/5">{allEpisodes.length} EPISODES</span>
                        </div>
                        <p className="text-slate-400 leading-relaxed text-sm font-medium line-clamp-4">{selectedAnime.synopsis}</p>
                     </div>

                     <div className="space-y-6 pt-6 border-t border-white/5">
                       <h3 className="text-xs font-black uppercase tracking-[0.4em] text-slate-500">Master List</h3>
                       <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-4 gap-3 max-h-[450px] overflow-y-auto pr-2 custom-scrollbar">
                         {displayedEpisodes.map(ep => (
                           <button
                             key={ep.mal_id}
                             onClick={() => handleSelectEpisode(ep)}
                             className="bg-slate-900/40 hover:bg-blue-600/10 border border-white/5 hover:border-blue-500/30 p-4 rounded-xl text-left transition-all group"
                           >
                             <div className="text-[8px] font-black text-slate-600 group-hover:text-blue-400 uppercase mb-1">Entry {ep.number}</div>
                             <div className="text-[10px] font-bold truncate text-slate-400 group-hover:text-white">Episode {ep.number}</div>
                           </button>
                         ))}
                       </div>

                       {displayedEpisodes.length < allEpisodes.length && (
                         <button onClick={loadMoreEpisodes} className="w-full py-4 bg-white/5 hover:bg-white/10 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all">
                           {isAppending ? 'Syncing...' : 'Load More Episodes'}
                         </button>
                       )}
                     </div>
                   </div>
                </div>
              )}
            </div>

            {availableSources.length > 0 && (
              <div className="w-full lg:w-96 space-y-6 sticky top-28 self-start animate-in fade-in slide-in-from-right-4">
                <h3 className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500 px-2">Sequential Queue</h3>
                <div className="max-h-[70vh] overflow-y-auto pr-4 space-y-3 custom-scrollbar">
                  {displayedEpisodes.map(ep => (
                    <button
                      key={ep.mal_id}
                      onClick={() => handleSelectEpisode(ep)}
                      className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all border ${selectedEpisode?.mal_id === ep.mal_id ? 'bg-blue-600/10 border-blue-500/50 shadow-2xl' : 'bg-slate-900/30 border-transparent hover:bg-slate-900 hover:border-white/5'}`}
                    >
                      <div className={`w-10 h-10 flex-shrink-0 flex items-center justify-center rounded-xl font-black text-[11px] ${selectedEpisode?.mal_id === ep.mal_id ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                        {ep.number}
                      </div>
                      <div className="text-left overflow-hidden">
                        <div className={`text-[10px] font-black uppercase truncate mb-1 ${selectedEpisode?.mal_id === ep.mal_id ? 'text-blue-400' : 'text-slate-300'}`}>
                          Episode {ep.number}
                        </div>
                        <div className="text-[8px] text-slate-600 font-bold uppercase tracking-widest">S1 • HD Stream</div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {!selectedAnime && !isSearching && !isInitialLoading && searchResults.length === 0 && (
          <div className="text-center py-52 space-y-10">
             <div className="relative inline-block">
                <div className="absolute inset-0 bg-blue-500/20 blur-[100px] animate-pulse"></div>
                <div className="relative p-14 bg-slate-900 rounded-[3.5rem] border border-white/5 shadow-3xl">
                   <PlayIcon size={80} className="text-blue-500" />
                </div>
             </div>
             <div className="space-y-4">
               <h2 className="text-7xl font-black tracking-tighter">ZENITH <span className="text-slate-700">PLAYER</span></h2>
               <p className="text-slate-500 font-black text-xs uppercase tracking-[0.6em]">Encrypted AES-128 Playback Engine • Secure Matrix</p>
             </div>
             <button onClick={() => {setSearchQuery('Naruto'); handleSearch();}} className="bg-blue-600 hover:bg-blue-500 px-14 py-6 rounded-full text-[10px] font-black uppercase tracking-[0.4em] transition-all shadow-2xl shadow-blue-600/30">
               Initialize Hub
             </button>
          </div>
        )}
      </main>

      <footer className="border-t border-white/5 py-10 opacity-30">
        <div className="container mx-auto px-6 text-center">
          <p className="text-[9px] font-black uppercase tracking-[0.6em]">Zenith Streaming Matrix &bull; Security Protocol Active</p>
        </div>
      </footer>
    </div>
  );
};

export default App;
